def _resolve_dynamic_defaults(self, ctx: Context) -> None:
    """Resolve options whose ``default`` is a mapping of other
    option declarations to value-keyed defaults, e.g.
    ``default={"--protocol": {"http": 80, "https": 443}}``.

    This runs after every parameter has consumed its command line
    argument, environment variable, and default map value, so the
    mapping can key off of the final values of the options it
    depends on. It only applies to options whose own value came
    from their static default (i.e. nothing else was provided).
    """
    params = self.get_params(ctx)

    for param in params:
        if not isinstance(param, Option) or not isinstance(param.default, dict):
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:
            continue

        resolved = None

        for opt_name, mapping in param.default.items():
            source_param = next(
                (
                    p
                    for p in params
                    if isinstance(p, Option)
                    and opt_name in (*p.opts, *p.secondary_opts)
                ),
                None,
            )

            if source_param is None:
                continue

            key = str(ctx.params.get(source_param.name))

            if key in mapping:
                resolved = mapping[key]

        if resolved is not None:
            with augment_usage_errors(ctx, param=param):
                value = param.process_value(ctx, resolved)

            if param.expose_value:
                ctx.params[param.name] = value

